#[cfg(test)]
mod tests {
    use super::*;
    use std::sync::Arc;
    use std::thread;

    #[test]
    fn test_concurrent_cell_basic() {
        let cell = ConcurrentCell::new(42u64);
        assert_eq!(cell.accessor_count(), 0);
        assert_eq!(cell.version(), 0);

        unsafe {
            let mut guard = cell.get_mut();
            assert_eq!(*guard, 42);
            *guard = 100;
        }

        assert_eq!(cell.version(), 1);
        assert_eq!(cell.accessor_count(), 0);

        let read_guard = cell.get_ref();
        assert_eq!(*read_guard, 100);
        assert!(!read_guard.is_stale());
    }

    #[test]
    fn test_concurrent_cell_snapshot() {
        let cell = ConcurrentCell::new(vec![1, 2, 3]);
        let snap = cell.snapshot();
        assert_eq!(snap, vec![1, 2, 3]);
    }

    #[test]
    fn test_concurrent_cell_multithreaded() {
        let cell = Arc::new(ConcurrentCell::new(AtomicUsize::new(0)));
        let mut handles = vec![];

        for _ in 0..4 {
            let cell_clone = Arc::clone(&cell);
            let handle = thread::spawn(move || {
                for _ in 0..1000 {
                    unsafe {
                        let guard = cell_clone.get_mut();
                        guard.fetch_add(1, Ordering::Relaxed);
                    }
                }
            });
            handles.push(handle);
        }

        for handle in handles {
            handle.join().unwrap();
        }

        let read_guard = cell.get_ref();
        assert_eq!(read_guard.load(Ordering::Relaxed), 4000);
    }

    #[test]
    fn test_concurrent_cell_apply() {
        let cell = ConcurrentCell::new(vec![1, 2, 3]);

        unsafe {
            cell.apply(|v| v.push(4));
        }

        let snap = cell.snapshot();
        assert_eq!(snap, vec![1, 2, 3, 4]);
        assert_eq!(cell.version(), 1);
    }

    #[test]
    fn test_concurrent_cell_read_staleness() {
        let cell = ConcurrentCell::new(10);
        let read_guard = cell.get_ref();
        assert!(!read_guard.is_stale());

        unsafe {
            let mut guard = cell.get_mut();
            *guard = 20;
        }

        assert!(read_guard.is_stale());
    }

    #[test]
    fn test_concurrent_cell_into_inner() {
        let cell = ConcurrentCell::new(String::from("hello"));
        let value = cell.into_inner();
        assert_eq!(value, "hello");
    }

    #[test]
    fn test_concurrent_vec_basic() {
        let vec = ConcurrentVec::new(4);
        assert!(vec.is_empty());

        unsafe {
            vec.push(10);
            vec.push(20);
            vec.push(30);
        }

        assert_eq!(vec.len(), 3);

        unsafe {
            assert_eq!(*vec.get(0).unwrap(), 10);
            assert_eq!(*vec.get(1).unwrap(), 20);
            assert_eq!(*vec.get(2).unwrap(), 30);
            assert!(vec.get(3).is_none());
        }
    }

    #[test]
    fn test_concurrent_vec_cross_chunk() {
        let vec = ConcurrentVec::new(2);

        unsafe {
            for i in 0..10 {
                vec.push(i);
            }
        }

        assert_eq!(vec.len(), 10);

        unsafe {
            for i in 0..10 {
                assert_eq!(*vec.get(i).unwrap(), i);
            }
        }
    }

    #[test]
    fn test_concurrent_vec_mut_access() {
        let vec = ConcurrentVec::new(8);

        unsafe {
            vec.push(1);
            vec.push(2);
            vec.push(3);

            let elem = vec.get_mut(1).unwrap();
            *elem = 42;

            assert_eq!(*vec.get(1).unwrap(), 42);
        }
    }

    #[test]
    fn test_concurrent_vec_drop() {
        use std::sync::atomic::AtomicUsize;

        static DROP_COUNT: AtomicUsize = AtomicUsize::new(0);

        #[derive(Debug)]
        struct DropCounter;

        impl Drop for DropCounter {
            fn drop(&mut self) {
                DROP_COUNT.fetch_add(1, Ordering::Relaxed);
            }
        }

        DROP_COUNT.store(0, Ordering::Relaxed);

        {
            let vec = ConcurrentVec::new(2);
            unsafe {
                vec.push(DropCounter);
                vec.push(DropCounter);
                vec.push(DropCounter);
            }
        }

        assert_eq!(DROP_COUNT.load(Ordering::Relaxed), 3);
    }
}